import modal

app = modal.App("nfs-demo")
nfs = modal.NetworkFileSystem.from_name("shared-fs", create_if_missing=True)

@app.function(network_file_systems={"/shared": nfs})
def write_shared_file():
    with open("/shared/message.txt", "w") as f:
        f.write("hello from nfs")

@app.function(network_file_systems={"/shared": nfs})
def read_shared_file():
    with open("/shared/message.txt", "r") as f:
        return f.read()

@app.local_entrypoint()
def main():
    write_shared_file.remote()
    result = read_shared_file.remote()
    with open("/home/user/modal_project/nfs_output.txt", "w") as f:
        f.write(result)

